import { GoogleGenAI } from "@google/genai";
import { Document, DocHistory } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const AIService = {
  analyzeDocumentHistory: async (doc: Document, history: DocHistory[]) => {
    const historySummary = history.map(h => `- ${h.timestamp}: ${h.action} por ${h.userName} (${h.comment})`).join('\n');

    const prompt = `
      Analiza el siguiente historial de un documento institucional:
      Título: ${doc.title}
      Estado Actual: ${doc.state}
      Versión: ${doc.version}
      Historial:
      ${historySummary}

      Proporciona un resumen ejecutivo de 3 líneas sobre el estado de este documento y una recomendación para el analista asignado.
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: prompt }] }],
      });
      return response.text;
    } catch (error) {
      console.error("Error calling Gemini:", error);
      return "No se pudo generar el análisis en este momento.";
    }
  },

  analyzeDashboardTrends: async (stats: any) => {
    const prompt = `
      Basado en estas estadísticas de gestión documental:
      Total Requeridos: ${stats.total}
      No Iniciados: ${stats.notStarted}
      En Proceso: ${stats.inProcess}
      En Referente: ${stats.referent}
      En Control: ${stats.control}
      Terminados: ${stats.finished}

      Identifica el principal riesgo de gestión y da una recomendación estratégica breve para la dirección.
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: prompt }] }],
      });
      return response.text;
    } catch (error) {
      console.error("Error calling Gemini:", error);
      return "Análisis de tendencias no disponible.";
    }
  }
};
